function heuristicSingleMessage(
  input: SingleCommitInput,
  config: PiAutocommitConfig,
): string {
  const fallback = generateCommitMessage(
    input.nameStatus,
    input.stat,
    input.diff,
    config,
  );
  return formatFullMessage(fallback);
